A text utility analyzes phrases. The PhraseScanner class is partially defined below.

public class PhraseScanner {
    private String phrase;

    public PhraseScanner(String p) {
        phrase = p;
    }

    /** Returns true if the single-character String ch is one of the
      * vowels "a", "e", "i", "o", or "u" (lowercase only). Otherwise returns
      * false.
      * Precondition: ch has length 1.
      */
    public boolean isVowel(String ch) { /* part (a) */ }

    /** Returns the number of words in phrase that begin with a vowel.
      * Words are separated by single spaces. The phrase has no leading or
      * trailing spaces. If phrase is null or the empty string, returns 0.
      * This method MUST call isVowel to test the first letter of each word.
      */
    public int countVowelWords() { /* part (b) */ }
}

frq_section.reference_solution:
public class PhraseScanner {
    private String phrase;

    public PhraseScanner(String p) {
        phrase = p;
    }

    public boolean isVowel(String ch) {
        return ch.equals("a") || ch.equals("e") || ch.equals("i")
            || ch.equals("o") || ch.equals("u");
    }

    public int countVowelWords() {
        if (phrase == null || phrase.length() == 0) return 0;
        int count = 0;
        String remaining = phrase;
        while (remaining.length() > 0) {
            int space = remaining.indexOf(" ");
            String word;
            if (space == -1) {
                word = remaining;
                remaining = "";
            } else {
                word = remaining.substring(0, space);
                remaining = remaining.substring(space + 1);
            }
            if (word.length() > 0 && isVowel(word.substring(0, 1))) {
                count++;
            }
        }
        return count;
    }
}

