public class SavingsGoal {
    private String goalName;
    private double targetAmount;
    private double currentAmount;
    private int priority;

    public SavingsGoal(String goalName, double targetAmount, double currentAmount, int priority) {
        this.goalName = goalName;
        this.targetAmount = targetAmount;
        this.currentAmount = currentAmount;
        this.priority = priority;
    }

    public SavingsGoal(String goalName, double targetAmount, int priority) {
        this.goalName = goalName;
        this.targetAmount = targetAmount;
        this.currentAmount = 0.0;
        this.priority = priority;
    }

    public void deposit(double amount) {
        currentAmount += amount;
    }

    public String getStatus() {
        String label;
        if (priority == 1) {
            label = "high priority";
        } else if (priority == 2) {
            label = "medium priority";
        } else {
            label = "low priority";
        }
        return goalName + ": $" + currentAmount + " of $" + targetAmount + " [" + label + "]";
    }
}

