frq_section.reference_solution:
import java.util.ArrayList;

class Donation {
    private String donor;
    private int books;
    public Donation(String d, int b) { donor = d; books = b; }
    public String getDonor() { return donor; }
    public int getBooks() { return books; }
}

class DonationLog {
    private ArrayList<Donation> log;

    public DonationLog() {
        log = new ArrayList<Donation>();
    }

    public boolean recordDonation(String donor, int books) {
        for (int i = 0; i < log.size(); i++) {
            if (log.get(i).getDonor().equals(donor)) {
                return false;
            }
        }
        log.add(new Donation(donor, books));
        return true;
    }

    public int totalFromTopDonors(int min) {
        recordDonation("Anonymous", 0);
        int total = 0;
        for (int i = 0; i < log.size(); i++) {
            if (log.get(i).getBooks() >= min) {
                total += log.get(i).getBooks();
            }
        }
        return total;
    }
}

